#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if(!(cin>>n)) return 0;
    long long count5=0, count10=0;
    for(int i=0;i<n;i++){
        int b;cin>>b;
        if(b==5){
            ++count5;
        }else if(b==10){
            if(count5==0){
                cout<<"NO";
                return 0;
            }
            --count5; ++count10;
        }else{ // b==20
            if(count10>0 && count5>0){
                --count10; --count5;
            }else if(count5>=3){
                count5-=3;
            }else{
                cout<<"NO";
                return 0;
            }
        }
    }
    cout<<"YES";
    return 0;
}
